SELECT
    SUM(CASE WHEN type = 1 THEN amount ELSE 0 END) as totalIncome,
    SUM(CASE WHEN type = 2 THEN amount ELSE 0 END) as totalExpense,
    COUNT(*) as totalCount
FROM t_transaction
WHERE user_id = #{userId}

    AND company_id = #{companyId}


    AND transaction_time >= #{startTime}


    AND transaction_time <= #{endTime}

SELECT * FROM t_transaction
WHERE user_id = #{userId}

    AND company_id = #{companyId}


    AND transaction_time >= #{startTime}


    AND transaction_time <= #{endTime}


    AND type = #{type}


    AND category_id = #{categoryId}

ORDER BY transaction_time DESC

SELECT category_id, SUM(amount) as totalAmount, COUNT(*) as count
FROM t_transaction
WHERE user_id = #{userId}

    AND company_id = #{companyId}


    AND transaction_time >= #{startTime}


    AND transaction_time <= #{endTime}


    AND type = #{type}

GROUP BY category_id ORDER BY totalAmount DESC

SELECT
    MONTH(transaction_time) as month,
    SUM(CASE WHEN type = 1 THEN amount ELSE 0 END) as income,
    SUM(CASE WHEN type = 2 THEN amount ELSE 0 END) as expense
FROM t_transaction
WHERE user_id = #{userId}

    AND company_id = #{companyId}

AND YEAR(transaction_time) = #{year}
GROUP BY MONTH(transaction_time)
ORDER BY month

SELECT
    SUM(CASE WHEN type = 1 THEN amount ELSE 0 END) as totalIncome,
    SUM(CASE WHEN type = 2 THEN amount ELSE 0 END) as totalExpense,
    COUNT(*) as transactionCount
FROM t_transaction
WHERE user_id = #{userId}

    AND company_id = #{companyId}

AND YEAR(transaction_time) = #{year}
